InitObjects:
local script = _G.initObjects

if not script then
    local partsWithId = {}
    local awaitRef = {}

    local root = {
        ID = 0;
        Type = "ModuleScript";
        Properties = {
            Name = "InitObjects";
        };
        Children = {
            {
                ID = 1;
                Type = "Part";
                Properties = {
                    BottomSurface = Enum.SurfaceType.Smooth;
                    Color = Color3.new(41/51,41/51,41/51);
                    CFrame = CFrame.new(46,3.4996271133423,6,1,0,0,0,1,0,0,0,1);
                    CustomPhysicalProperties = PhysicalProperties.new(0.69999998807907,0,0,1,100);
                    Name = "Sphere";
                    Transparency = 1;
                    brickColor = BrickColor.new(41/51,41/51,41/51);
                    Position = Vector3.new(46,3.4996271133423,6);
                    BrickColor = BrickColor.new(41/51,41/51,41/51);
                    Size = Vector3.new(2,2,2);
                    Shape = Enum.PartType.Ball;
                    TopSurface = Enum.SurfaceType.Smooth;
                };
                Children = {};
            };
            {
                ID = 2;
                Type = "BodyGyro";
                Properties = {
                    P = 25000;
                    MaxTorque = Vector3.new(100000,100000,100000);
                    maxTorque = Vector3.new(100000,100000,100000);
                };
                Children = {};
            };
            {
                ID = 3;
                Type = "VectorForce";
                Properties = {
                    RelativeTo = Enum.ActuatorRelativeTo.World;
                    Force = Vector3.new();
                    ApplyAtCenterOfMass = true;
                };
                Children = {};
            };
            {
                ID = 4;
                Type = "Part";
                Properties = {
                    Size = Vector3.new(2,1,1);
                    Transparency = 1;
                    Name = "Floor";
                    CanCollide = false;
                    BottomSurface = Enum.SurfaceType.Smooth;
                    CFrame = CFrame.new(24,0.5,-27.5,1,0,0,0,1,0,0,0,1);
                    Position = Vector3.new(24,0.5,-27.5);
                    TopSurface = Enum.SurfaceType.Smooth;
                };
                Children = {};
            };
        };
    };

    local function Scan(item, parent)
        local obj = Instance.new(item.Type)
        if (item.ID) then
            local awaiting = awaitRef[item.ID]
            if (awaiting) then
                awaiting[1][awaiting[2]] = obj
                awaitRef[item.ID] = nil
            else
                partsWithId[item.ID] = obj
            end
        end
        for p,v in pairs(item.Properties) do
            if (type(v) == "string") then
                local id = tonumber(v:match("^_R:(%w+)_$"))
                if (id) then
                    if (partsWithId[id]) then
                        v = partsWithId[id]
                    else
                        awaitRef[id] = {obj, p}
                        v = nil
                    end
                end
            end
            obj[p] = v
        end
        for _,c in pairs(item.Children) do
            Scan(c, obj)
        end
        obj.Parent = parent
        return obj
    end

    script = Scan(root, nil)
    _G.initObjects = script
end

local SPHERE = script:WaitForChild("Sphere")
local FLOOR = script:WaitForChild("Floor")
local VFORCE = script:WaitForChild("VectorForce")
local BGYRO = script:WaitForChild("BodyGyro")

local function initObjects(self)
	local hrp = self.HRP
	local humanoid = self.Humanoid
	
	local sphere = SPHERE:Clone()
	sphere.Parent = self.Character
	
	local floor = FLOOR:Clone()
	floor.Parent = self.Character
	
	local isR15 = (humanoid.RigType == Enum.HumanoidRigType.R15)
	local height = isR15 and (humanoid.HipHeight + 0.05) or 2
	
	local weld = Instance.new("Weld")
	weld.C0 = CFrame.new(0, -height, 0.1)
	weld.Part0 = hrp
	weld.Part1 = sphere
	weld.Parent = sphere
	
	local weld2 = Instance.new("Weld")
	weld2.C0 = CFrame.new(0, -(height + 1.5), 0)
	weld2.Part0 = hrp
	weld2.Part1 = floor
	weld2.Parent = floor
	
	local gyro = BGYRO:Clone()
	gyro.CFrame = hrp.CFrame
	gyro.Parent = hrp
	
	local vForce = VFORCE:Clone()
	vForce.Attachment0 = isR15 and hrp:WaitForChild("RootRigAttachment") or hrp:WaitForChild("RootAttachment")
	vForce.Parent = hrp
	
	return sphere, gyro, vForce, floor
end

return initObjects
